/**
 * NORMALIZADOR DE FATURA - BUSCA DIRETA NA FONTE
 */

// 1. CAPTURA DADOS DO WEBHOOK (Referência corrigida para 'Webhook')
let accountId = "";
let bankName = "";
let accountName = "";

try {
  const webData = $('Webhook').first().json.body;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
  accountName = webData.accountName || "Conta";
} catch (e) {
  bankName = "Banco";
}

const nomeContaCompleto = `${bankName} - ${accountName}`;

// 2. BUSCA A LISTA DIRETAMENTE NA I.A. (Evita o erro do Supabase no meio)
let listaBruta = [];
try {
    const aiData = $('LLM Chain PDF10').first().json;
    listaBruta = aiData.output || (Array.isArray(aiData) ? aiData : []);
} catch (e) {
    return [{ json: { erro: "Não foi possível encontrar os dados da LLM Chain PDF10" } }];
}

if (listaBruta.length === 0) {
    return [{ json: { aviso: "Lista de transações vazia." } }];
}

// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();

const resultado = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  const valorOriginal = parseFloat(item.v) || 0;
  const sinal = item.s || "+";

  // Inversão de sinal para o banco (Compra = negativo)
  let valorFinal = (sinal === "-") ? Math.abs(valorOriginal) : -Math.abs(valorOriginal);

  let dataISO = item.d || "";
  if (dataISO.includes('/')) {
    const p = dataISO.split('/');
    dataISO = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  return {
    json: {
      account_id: accountId,
      Conta: nomeContaCompleto,
      Data_lancamento: dataISO,
      Data_pagamento: dataISO,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : "receita",
      Categoria: item.c || "outros-gv",
      Classificacao: item.c || "outros-gv",
      p: item.p || null,
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});

// 4. FILTRO DE TOTAIS
return resultado.filter(res => {
  const d = res.json.Descricao;
  const ignorar = ["TOTAL", "SUBTOTAL", "RESUMO", "PAGAMENTO EFETUADO"];
  return !ignorar.some(p => d.includes(p)) && d !== "";
});

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

// Agora você extrai tudo de dentro da variável webhookData
const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];

const finalResults = [];
const hoje = new Date();
hoje.setHours(12, 0, 0, 0);
const hojeIso = hoje.toISOString().split('T')[0];

function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

let userIdFixo = "";
let webhookData = {};
try {
  webhookData = $('Webhook Original').first().json.body;
  try { userIdFixo = $('Code in JavaScript1').item.json.userId; } 
  catch (e) { userIdFixo = $('Code in JavaScript').item.json.userId; }
} catch (e) { userIdFixo = webhookData.userId || ""; }

const ownerIdCalculado = webhookData.ownerId || userIdFixo;

for (const item of $input.all()) {
  const transacao = item.json;
  const descOriginal = (transacao.Descricao || "").toUpperCase();
  const parcelaIA = (transacao.p || "").toString().toUpperCase();

  const regex = /(\d+)\s*[\/\-de\s]+\s*(\d+)/i;
  const match = parcelaIA.match(regex) || descOriginal.match(regex);

  const dataLancamentoLimpa = transacao.Data_lancamento.includes('T') ? transacao.Data_lancamento.split('T')[0] : transacao.Data_lancamento;

  if (match) {
    const parcelaAtual = parseInt(match[1]);
    const totalParcelas = parseInt(match[2]);
    const descLimpa = descOriginal.replace(/\(\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)/gi, '').replace(regex, '').replace(/\s+/g, ' ').trim();
    const installmentGroupId = generateUUID();

    const inicioLoop = parcelaAtual === 1 ? 0 : 0; 
    const fimLoop = totalParcelas - parcelaAtual;

    const dataBase = new Date(dataLancamentoLimpa + 'T12:00:00');

    for (let i = 0; i <= fimLoop; i++) {
      let dP = new Date(dataBase);
      dP.setMonth(dataBase.getMonth() + i);
      const dt = dP.toISOString().split('T')[0];

      const isFuturo = dt > hojeIso;

      finalResults.push({
        json: {
          ...transacao,
          Descricao: `${descLimpa} (${parcelaAtual + i}/${totalParcelas})`,
          Data_lancamento: dt,
          userId: userIdFixo,
          accountId: webhookData.accountId,
          ownerId: ownerIdCalculado,
          confirmed: !isFuturo, 
          paymentDate: isFuturo ? null : webhookData.paymentDate,
          pending_review: true,
          installment_group_id: installmentGroupId,
          installment_number: parcelaAtual + i,
          total_installments: totalParcelas
        }
      });
    }
    continue;
  }

  const dataFinalIso = new Date(dataLancamentoLimpa + 'T12:00:00').toISOString().split('T')[0];
  const isFuturoSimples = dataFinalIso > hojeIso;

  finalResults.push({
    json: {
      ...transacao,
      Data_lancamento: dataFinalIso,
      userId: userIdFixo,
      accountId: webhookData.accountId,
      ownerId: ownerIdCalculado,
      paymentDate: isFuturoSimples ? null : webhookData.paymentDate,
      confirmed: !isFuturoSimples,
      pending_review: false,
      installment_group_id: null,
      installment_number: null,
      total_installments: null
    }
  });
}

return finalResults;

/**
 * NORMALIZADOR UNIVERSAL (PEGA TUDO O QUE CHEGAR)
 */

// 1. DADOS DA CONTA
let accountId = "";
let bankName = "";
try {
  const webhook = $('Webhook').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) { bankName = "Banco"; }

// 2. CAPTURA DE DADOS (ABERTURA DE ENVELOPE)
let listaBruta = [];
const incomingData = $input.all();

for (const item of incomingData) {
  const data = item.json;

  // Tenta encontrar a lista de transações em qualquer lugar
  let alvo = data.output || data;

  if (Array.isArray(alvo)) {
    listaBruta = listaBruta.concat(alvo);
  } else if (typeof alvo === 'object' && (alvo.t || alvo.d)) {
    listaBruta.push(alvo);
  }
}

// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (item.s === "-" || item.s === "despesa") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);

  let dataF = item.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    dataF = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno"].includes(item.c) ? "neutro" : "receita"),
      Categoria: item.c || "outros-gv",
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});

return final;

// Puxa os dados originais direto do Webhook (usando .first() para garantir)
const webhookData = $('Webhook').first().json.body;

const base64 = webhookData.file; 
const fileName = webhookData.fileName;
const userId = webhookData.userId;
const fileType = webhookData.fileType;

const binaryData = Buffer.from(base64, 'base64');

return [{
  json: {
    fileName: fileName,
    fileType: fileType,
    userId: userId
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      binaryData,
      fileName,
      fileType
    )
  }
}];

try {
  const input = $input.first();
  // Pega o tipo (se o nome do campo no form também tiver mudado, ajuste aqui se necessário)
  const tipo = input.json.tipo || input.json.Tipo_de_Documento || "extrato";

  // Proteção 1: Agora procurando pela chave exata que está na sua imagem (Arquivo_PDF)
  if (!input.binary || !input.binary.Arquivo_PDF) {
    throw new Error("❌ Nenhum arquivo foi enviado! Volte no formulário e anexe o PDF.");
  }

  const binaryData = input.binary.Arquivo_PDF;

  // Proteção 2: Pega o buffer com segurança usando a chave certa
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'Arquivo_PDF');
  const base64 = buffer.toString('base64');

  return [{
    json: {
      body: {
        tipo: tipo,
        file: base64,
        fileName: binaryData.fileName,
        fileType: binaryData.mimeType,
        userId: "11111111-1111-1111-1111-111111111111",
        accountId: "22222222-2222-2222-2222-222222222222",
        ownerId: "33333333-3333-3333-3333-333333333333",
        jobId: "44444444-4444-4444-4444-444444444444",
        accountName: "Conta Teste",
        bankName: "Banco Teste"
      }
    }
  }];
} catch (error) {
  throw new Error("Erro no Webhook de Teste: " + error.message);
}

