/**
 * NORMALIZADOR DE FATURA - INTELIGÊNCIA UNIVERSAL ANTI-PROJEÇÃO
 */

// 1. CAPTURA DADOS DO WEBHOOK
let accountId = "";
let bankName = "";
let accountName = "";

try {
  const webData = $('Webhook1').first().json.body;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
  accountName = webData.accountName || "Conta";
} catch (e) {
  bankName = "Banco";
}

const nomeContaCompleto = `${bankName} - ${accountName}`;

// 2. BUSCA A LISTA DIRETA DA I.A.
let listaBruta = [];
try {
    const aiData = $('LLM Chain PDF2').first().json;
    listaBruta = aiData.output || (Array.isArray(aiData) ? aiData : []);
} catch (e) {
    return [{ json: { erro: "Não foi possível encontrar os dados da LLM Chain" } }];
}

if (listaBruta.length === 0) {
    return [{ json: { aviso: "Lista de transações vazia." } }];
}

const anoAtual = new Date().getFullYear();
const resultado = [];
const parcelamentosVistos = new Map(); // Guarda a assinatura de parcelas para barrar as tabelas do futuro

// 3. MAPEAMENTO E INTELIGÊNCIA DE FILTRO
listaBruta.forEach((item, index) => {
  const descOriginal = (item.t || "").toString().toUpperCase().trim();
  const valorOriginal = parseFloat(item.v) || 0;
  const sinal = item.s || "+";
  let valorFinal = (sinal === "-") ? Math.abs(valorOriginal) : -Math.abs(valorOriginal);

  let dataISO = item.d || "";
  if (dataISO.includes('/')) {
    const p = dataISO.split('/');
    dataISO = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }

  const p = item.p || null;

  // --- TRAVA UNIVERSAL DE PROJEÇÃO DE BANCOS ---
  if (p) {
    const match = p.match(/(\d+)\s*[\/\-de\s]+\s*(\d+)/);
    if (match) {
      const parcelaAtual = parseInt(match[1], 10);
      const totalParcelas = match[2];

      // Cria uma assinatura ignorando os números das parcelas no texto para focar na "raiz" da compra
      const descLimpa = descOriginal.replace(/\(?\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)?/g, '').trim();
      const assinatura = `${descLimpa}_${valorFinal}_${totalParcelas}`;

      if (parcelamentosVistos.has(assinatura)) {
        const parcelaRegistrada = parcelamentosVistos.get(assinatura);

        // Se a parcela que estamos lendo agora for MAIOR que a registrada antes, 
        // é 100% de certeza que o banco começou a listar o futuro (Ex: leu 06/10 antes, e agora achou 07/10).
        if (parcelaAtual > parcelaRegistrada) {
          return; // Aborta e pula para a próxima linha (não gera duplicata)
        }
      }

      // Se for a primeira vez que vemos essa compra, salva a parcela atual dela no 'Map'
      parcelamentosVistos.set(assinatura, parcelaAtual);
    }
  }

  // --- SE PASSOU PELO FILTRO, ADICIONA À LISTA FINAL ---
  resultado.push({
    json: {
      account_id: accountId,
      Conta: nomeContaCompleto,
      Data_lancamento: dataISO,
      Data_pagamento: dataISO,
      Descricao: descOriginal,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : "receita",
      Categoria: item.c || "outros-gv",
      Classificacao: item.c || "outros-gv",
      p: p,
      id_conciliacao: `${descOriginal}-${valorFinal}-${index}`
    }
  });
});

// 4. FILTRO FINAL DE TOTAIS SUJOS
return resultado.filter(res => {
  const d = res.json.Descricao;
  const ignorar = ["TOTAL", "SUBTOTAL", "RESUMO", "PAGAMENTO EFETUADO", "SALDO ANTERIOR"];
  return !ignorar.some(p => d.includes(p)) && d !== "";
});

