  try {
    const transacao = item.json;

    // Garantia de tipos (Strings) para evitar quebras em métodos como .match()
    const descOriginal = String(transacao.Descricao || "").toUpperCase();
    const parcelaIA = String(transacao.p || "").toUpperCase();
    const dataRaw = String(transacao.Data_lancamento || "");

    if (!dataRaw) continue; // Pula se o item não tiver data

    const regex = /(\d+)\s*[\/\-de\s]+\s*(\d+)/i;
    const match = parcelaIA.match(regex) || descOriginal.match(regex);

    // Limpeza da data (remove o tempo se vier no formato ISO)
    const dataLancamentoLimpa = dataRaw.includes('T') ? dataRaw.split('T')[0] : dataRaw;

    // --- LÓGICA DE PROTEÇÃO CONTRA DATAS QUE PARECEM PARCELAS ---
    let isValidInstallment = false;
    if (match) {
      const pAtual = parseInt(match[1]);
      const pTotal = parseInt(match[2]);

      // Só aceita como parcela se o total for maior que a atual e se não for um PIX com data (ex: 06/01)
      if (pAtual <= pTotal && pTotal > 1) {
         // Se for PIX e não houver instrução explícita da IA (campo p), ignoramos o match da descrição
         if (descOriginal.includes("PIX") && !transacao.p) {
           isValidInstallment = false;
         } else {
           isValidInstallment = true;
         }
      }
    }

    if (isValidInstallment && match) {
      const parcelaAtual = parseInt(match[1]);
      const totalParcelas = parseInt(match[2]);
      const descLimpa = descOriginal.replace(/\(\s*\d+\s*[\/\-de\s]+\s*\d+\s*\)/gi, '').replace(regex, '').replace(/\s+/g, ' ').trim();
      const installmentGroupId = generateUUID();

      const fimLoop = totalParcelas - parcelaAtual;
      const dataBase = new Date(dataLancamentoLimpa + 'T12:00:00');

      for (let i = 0; i <= fimLoop; i++) {
        let dP = new Date(dataBase);
        dP.setMonth(dataBase.getMonth() + i);
        const dt = dP.toISOString().split('T')[0];
        const isFuturo = dt > hojeIso;

        finalResults.push({
          json: {
            ...transacao,
            Descricao: `${descLimpa} (${parcelaAtual + i}/${totalParcelas})`,
            Data_lancamento: dt,
            userId: userIdFixo,
            accountId: webhookData.accountId,
            ownerId: ownerIdCalculado,
            confirmed: !isFuturo, 
            paymentDate: isFuturo ? null : (webhookData.paymentDate || transacao.Data_pagamento || null),
            pending_review: true,
            installment_group_id: installmentGroupId,
            installment_number: parcelaAtual + i,
            total_installments: totalParcelas
          }
        });
      }
      continue; // Vai para o próximo item do $input.all()
    }

    // --- CASO NORMAL (SEM PARCELAS OU DATA QUE PARECIA PARCELA) ---
    const dataFinalIso = new Date(dataLancamentoLimpa + 'T12:00:00').toISOString().split('T')[0];
    const isFuturoSimples = dataFinalIso > hojeIso;

    finalResults.push({
      json: {
        ...transacao,
        Data_lancamento: dataFinalIso,
        userId: userIdFixo,
        accountId: webhookData.accountId,
        ownerId: ownerIdCalculado,
        paymentDate: isFuturoSimples ? null : (webhookData.paymentDate || transacao.Data_pagamento || null),
        confirmed: !isFuturoSimples,
        pending_review: false,
        installment_group_id: null,
        installment_number: null,
        total_installments: null
      }
    });

  } catch (err) {
    // Em caso de erro em um item (ex: data inválida), loga o erro e continua para o próximo item
    console.error("Erro ao processar item:", err);
    continue; 
  }
}

return finalResults;

// Busca o texto diretamente do nó de extração, não do nó anterior
const text = $('Extract from File3').item.json.text || "";
const lines = text.split('\n'); // Divide o texto em linhas reais
const maxCharsPerChunk = 10000; // Limite de segurança
let currentChunk = "";
const chunks = [];

for (const line of lines) {
    // Se a linha atual + o que já temos passar do limite, fecha o lote
    if ((currentChunk.length + line.length) > maxCharsPerChunk && currentChunk.length > 0) {
        chunks.push({ json: { textChunk: currentChunk } });
        currentChunk = "";
    }
    currentChunk += line + "\n";
}

// Adiciona o último pedaço que sobrou
if (currentChunk.length > 0) {
    chunks.push({ json: { textChunk: currentChunk } });
}

return chunks;

